import (
	"fmt"
	"math"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript script to calculate a discount based on order properties.
// The keys in the `order` map are injected as global variables into the JavaScript VM.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Initialize a new Goja JavaScript Virtual Machine
	vm := goja.New()

	// Inject the order object itself into the VM's global scope
	err := vm.Set("order", order)
	if err != nil {
		return 0, fmt.Errorf("failed to set global variable 'order': %w", err)
	}

	// Inject each key-value pair from the order map into the VM's global scope
	for key, value := range order {
		err = vm.Set(key, value)
		if err != nil {
			return 0, fmt.Errorf("failed to set global variable '%s': %w", key, err)
		}
	}

	// Set up a timeout to prevent infinite loops (DoS protection)
	timer := time.AfterFunc(1*time.Second, func() {
		vm.Interrupt("script execution timeout")
	})
	defer timer.Stop()

	// Execute the JavaScript code
	result, err := vm.RunString(script)
	if err != nil {
		return 0, fmt.Errorf("failed to execute script: %w", err)
	}

	// Convert the result to a float64
	// ToFloat converts the JS value to a float64 according to standard JavaScript rules.
	discount := result.ToFloat()

	// Handle cases where the script doesn't return a valid number (NaN)
	if math.IsNaN(discount) {
		return 0, fmt.Errorf("script did not return a valid number")
	}

	return discount, nil
}

func main() {
	// Define a sample order
	order := map[string]interface{}{
		"total":         250.50,
		"isMember":      true,
		"customerLevel": "gold",
		"itemCount":     5,
	}

	// Define a JavaScript rule
	// E.g., Gold members get 15% off if they spend over 200, otherwise 5% off.
	// Regular members get 10% off if they buy 5 or more items.
	script := `
		var discount = 0;
		if (isMember) {
			if (customerLevel === 'gold' && total > 200) {
				discount = total * 0.15;
			} else {
				discount = total * 0.05;
			}
		} else if (itemCount >= 5) {
			discount = total * 0.10;
		}

		// The last evaluated expression is the return value of the script
		discount;
	`

	// Calculate the discount
	discountAmount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error calculating discount: %v\n", err)
		return
	}

	fmt.Printf("Order Total: $%.2f\n", order["total"])
	fmt.Printf("Calculated Discount: $%.2f\n", discountAmount)
	fmt.Printf("Final Price: $%.2f\n", order["total"].(float64)-discountAmount)
}

